import screen from '@kyokuya/_shared/util/screen'
import type { IParticleEffectBubbleProps } from '@kyokuya/particle-bubble'
import { ParticleEffectBubble } from '@kyokuya/particle-bubble'
import { useParticleEffect2D } from '@kyokuya/particle-helper'
import cn from 'clsx'
import PropTypes from 'prop-types'
import React from 'react'
import SwipeableViews from 'react-swipeable-views'
import type { MagicPanelType } from '../context'
import { LayoutPostActionType, useLayoutPostContext } from '../context'
import AboutMePanel from './AboutMePanel'
import NavigationPanel from './NavigationPanel'
import SearchPanel from './SearchPanel'

const bubbleOptions: IParticleEffectBubbleProps = {}

export interface MagicPanelProps {
  /**
   * Navigation.
   */
  nav?: React.ReactNode
}

interface MagicPanelItem {
  type: MagicPanelType
  title: string
  element: React.ReactElement
}

export const MagicPanel: React.FC<MagicPanelProps> = props => {
  const { nav } = props
  const [dispatch, magicPanelVisible, magicPanelActivated] = useLayoutPostContext(
    ({ state, dispatch }) => [dispatch, state.magicPanelVisible, state.magicPanelActivated],
  )
  const magicPanelRef = React.useRef<HTMLDivElement>(null)

  const openPanel = React.useCallback(
    (panelType: MagicPanelType) =>
      dispatch({
        type: LayoutPostActionType.ACTIVE_MAGIC_PANEL,
        payload: { panel: panelType },
      }),
    [dispatch],
  )

  const panels: ReadonlyArray<MagicPanelItem> = React.useMemo(
    () => [
      {
        type: 'navigation',
        title: '目录',
        element: <NavigationPanel key="navigation">{nav}</NavigationPanel>,
      },
      {
        type: 'search',
        title: '检索',
        element: <SearchPanel key="search" />,
      },
      {
        type: 'about-me',
        title: '关于我',
        element: <AboutMePanel key="about-me" />,
      },
    ],
    [nav],
  )

  const onMagicPanelSwiped = React.useCallback(
    (activatedIndex: number): void => {
      const magicPanelType: MagicPanelType = panels[activatedIndex].type
      if (magicPanelType === undefined) return
      dispatch({
        type: LayoutPostActionType.ACTIVE_MAGIC_PANEL,
        payload: { panel: magicPanelType },
      })
    },
    [dispatch, panels],
  )

  // Use particle effect when magic-panel is visible.
  useParticleEffect2D<IParticleEffectBubbleProps>(
    screen.lg ? null : magicPanelRef,
    ParticleEffectBubble,
    bubbleOptions,
    magicPanelVisible,
  )

  const magicPanelActivatedIndex: number = Math.max(
    0,
    panels.findIndex(panel => panel.type === magicPanelActivated),
  )

  const panelNavItems: React.ReactElement[] = []
  for (let i = 0; i < panels.length; ++i) {
    if (i > 0) {
      panelNavItems.push(
        <span key={`delimiter-${i}`} className="kyokuya-post-magic-panel__nav-delimiter" />,
      )
    }

    const panel = panels[i]
    panelNavItems.push(
      <span
        key={panel.type}
        className={cn('kyokuya-post-magic-panel__nav-item', {
          'kyokuya-post-magic-panel__nav-item--active': magicPanelActivated === panel.type,
        })}
        onClick={() => openPanel(panel.type)}
      >
        {panel.title}
      </span>,
    )
  }

  return (
    <div
      ref={magicPanelRef}
      className={cn(
        'kyokuya-post-magic-panel',
        { 'kyokuya-post-magic-panel--visible': magicPanelVisible },
        'kyokuya-post__frosted-glass-panel',
      )}
      onClick={e => void e.stopPropagation()}
    >
      <div className="kyokuya-post-magic-panel__header">
        <div className="kyokuya-post-magic-panel__nav">{panelNavItems}</div>
      </div>
      <div className="kyokuya-post-magic-panel__main">
        <SwipeableViews
          index={magicPanelActivatedIndex}
          onChangeIndex={onMagicPanelSwiped}
          containerStyle={{ height: '100%' }}
          style={{ height: '100%' }}
        >
          {panels.map(panel => panel.element)}
        </SwipeableViews>
      </div>
    </div>
  )
}

MagicPanel.propTypes = {
  nav: PropTypes.node,
}

MagicPanel.displayName = 'KyokuyaLayoutPostMagicPanel'
export default MagicPanel
