import { noEffectAssign } from '@kyokuya/core-util'
import type { IPostItem, MagicPanelType } from './types'

export interface ILayoutPostState {
  /**
   * Whether if enable the darken mode
   */
  darken: boolean
  /**
   * Page brightness
   */
  brightness: number
  /**
   * All of post tags.
   */
  tags: ReadonlyArray<string>
  /**
   * All of post items.
   */
  posts: ReadonlyArray<IPostItem>
  /**
   * Keyword in the searching panel.
   */
  searchingKeyword: string
  /**
   * Whether if the tags-list on the searching panel is visible
   */
  searchingTagsVisible: boolean
  /**
   * Whether to display the magic-panel.
   */
  magicPanelVisible: boolean
  /**
   * Which magic-panel should be displayed.
   */
  magicPanelActivated: MagicPanelType
}

export type ILayoutPostData = ILayoutPostState

export const initLayoutPostState = (
  customizedData?: Partial<ILayoutPostData> | null,
  baseState: Readonly<ILayoutPostState> = defaultLayoutPostState,
): ILayoutPostState => {
  const posts = (customizedData?.posts ?? baseState.posts)?.slice()
  const tagSet: Set<string> = new Set()
  for (const post of posts) {
    for (const tag of post.tags) tagSet.add(tag)
  }
  const tags: ReadonlyArray<string> = Array.from(tagSet).sort()

  return {
    ...noEffectAssign(baseState, customizedData ?? undefined),
    tags,
    posts,
  }
}

export const defaultLayoutPostState: ILayoutPostState = {
  darken: false,
  brightness: 100,
  tags: [],
  posts: [],
  searchingKeyword: '',
  searchingTagsVisible: false,
  magicPanelVisible: false,
  magicPanelActivated: 'navigation',
}
