import { pick } from '@kyokuya/core-util'
import { createSelectableContext } from '@kyokuya/react-hooks'
import { createPersistProvider } from '@kyokuya/react-storage'
import type React from 'react'
import type { ILayoutPostAction } from './action'
import { LayoutPostLayoutComponent } from './LayoutComponent'
import { layoutPostReducer } from './reducer'
import type { ILayoutPostData, ILayoutPostState } from './state'
import { initLayoutPostState } from './state'

/**
 * Side-effect funcs provided by the LayoutPostContextType.
 */
export interface ILayoutPostContext {
  state: ILayoutPostState
  dispatch: React.Dispatch<ILayoutPostAction | ILayoutPostAction[]>
}

/**
 * Create post layout context.
 */
const [LayoutPostContextType, useLayoutPostContext] = createSelectableContext<ILayoutPostContext>(
  'LayoutPostContextType',
  {
    state: initLayoutPostState(),
    dispatch: (): void => {
      throw new Error('[LayoutPostContextType] dispatch is not available yet.')
    },
  },
)

export { useLayoutPostContext }

export const LayoutPostContextProvider = createPersistProvider<
  ILayoutPostState,
  ILayoutPostAction,
  ILayoutPostData
>({
  ContextName: 'LayoutPostContext',
  ContextType: LayoutPostContextType,
  useContext: useLayoutPostContext,
  initState: initLayoutPostState,
  reducer: layoutPostReducer,
  serialize: state =>
    pick(state, [
      'darken',
      'brightness',
      'searchingKeyword',
      'searchingTagsVisible',
      'magicPanelVisible',
      'magicPanelActivated',
    ]),
  LayoutComponent: LayoutPostLayoutComponent,
})
