import { useDeepCompareMemo } from '@guanghechen/react-hooks'
import Link from '@kyokuya/react-link'
import { ArrowRightAltOutlined } from '@mui/icons-material'
import type {
  Definition as IDefinition,
  EcmaImport as IEcmaImport,
  FootnoteDefinition as IFootnoteDefinition,
  Root as IRoot,
} from '@yozora/ast'
import cn from 'clsx'
import React from 'react'
import { SeoPageDescription } from '@/component/SeoPageDescription'
import Toc from '@/component/toc'
import type { TocItemData } from '@/component/toc'
import useActivatedIdentifier from '@/core/hook/useActivatedIdentifier'
import { resolveIdentifier } from '@/core/util/url'
import { Layout } from '../component/Layout'
import { Pagination } from '../component/Pagination'
import { PostContent } from '../component/PostContent'
import { LayoutPostContextProvider } from '../context'
import type { ILayoutPostData, IPostItem } from '../context'
import LayoutPostMarkdownProvider from './_MarkdownProvider'

export interface PostListPageQueryContext {
  /**
   * Current page number.
   */
  current: number
  /**
   * Count of total pages.
   */
  totalPage: number
  /**
   * Url prefix of post pagination page.
   */
  urlPrefix: string
}

export interface PostListPageProps extends PostListPageQueryContext {
  posts?: Array<{
    title?: string
    description?: string
    createAt: string
    updateAt: string
    timeToRead: string
    categories: string[]
    tags: string[]
    ecmaImports: IEcmaImport[]
    definitionMap: Record<string, IDefinition>
    footnoteDefinitionMap: Record<string, IFootnoteDefinition>
    excerptAst: IRoot
    fields?: {
      slug?: string
    }
  }> | null
  postItems?: IPostItem[] | null
}

export function PostListPage(props: PostListPageProps): React.ReactElement {
  const { current, totalPage, urlPrefix, posts: initialPosts, postItems: initialPostItems } = props

  const resolveUrl = React.useMemo<(pageNo: number) => string | null>(() => {
    const prefix = (urlPrefix + '/').replace(/[/]+/g, '/')
    return (pageNo: number): string | null => {
      if (pageNo <= 0 || pageNo > totalPage) return null
      return prefix + '' + pageNo
    }
  }, [urlPrefix, totalPage])

  const { activatedIdentifier, refreshActivatedIdentifier, pauseWatchingScroll } =
    useActivatedIdentifier('kyokuya-post-list__post', 0)

  const { postItems, tocNodes, articles, description } = (() => {
    const tocNodes: TocItemData[] = []
    const articles: React.ReactElement[] = []
    const posts = initialPosts ?? []
    const postItems = initialPostItems as IPostItem[]
    const descriptions: string[] = []

    for (const post of posts) {
      const {
        title,
        createAt,
        updateAt,
        timeToRead,
        excerptAst,
        ecmaImports,
        definitionMap,
        footnoteDefinitionMap,
        tags,
      } = post
      const slug: string = post.fields!.slug ?? ''

      const tocItem: TocItemData = {
        depth: 1,
        identifier: 'post-' + resolveIdentifier(title ?? slug),
        title,
      }

      const article: React.ReactElement = (
        <LayoutPostMarkdownProvider
          key={tocItem.identifier}
          ecmaImports={ecmaImports}
          definitionMap={definitionMap}
          footnoteDefinitionMap={footnoteDefinitionMap}
        >
          <div id={tocItem.identifier} className="kyokuya-post-list__post">
            <PostContent
              title={title!}
              createAt={createAt!}
              updateAt={updateAt!}
              timeToRead={timeToRead!}
              tags={tags! as any}
              ast={excerptAst}
              slug={slug}
              shouldRenderFooter={false}
            />
            <Link url={slug} title={title!} itemProp="url" className="kyokuya-post-list__read-more">
              <span itemProp="headline" aria-label={title!}>
                阅读全文
              </span>
              <ArrowRightAltOutlined />
            </Link>
          </div>
        </LayoutPostMarkdownProvider>
      )

      if (title != null) descriptions.push(title)
      tocNodes.push(tocItem)
      articles.push(article)
    }
    return {
      postItems,
      tocNodes,
      articles,
      description: descriptions.join('\n\n'),
    }
  })()

  const customizedData = useDeepCompareMemo<Partial<ILayoutPostData>>(
    () => ({ posts: postItems }),
    [postItems],
  )

  return (
    <LayoutPostContextProvider initialData={customizedData} storageKey="@/page/posts:post_layout">
      <Layout
        onScroll={refreshActivatedIdentifier}
        head={<SeoPageDescription title={'博文列表-' + current} description={description} />}
        content={
          <div className="kyokuya-post-list">
            {articles}
            <div
              className={cn('kyokuya-post-list__pagination', 'kyokuya-post__frosted-glass-panel')}
            >
              <Pagination totalPage={totalPage} current={current} resolveUrl={resolveUrl} />
            </div>
          </div>
        }
        nav={
          <Toc
            activatedIdentifier={activatedIdentifier}
            nodes={tocNodes}
            pauseWatchingScroll={pauseWatchingScroll}
          />
        }
      />
    </LayoutPostContextProvider>
  )
}

PostListPage.displayName = 'KyokuyaLayoutPostPostListPage'
export default PostListPage
